// MARK: - Test helpers

@MainActor
private final class MockRouter: InterPanelRouter {
    var events: AsyncStream<PanelEvent> { AsyncStream { _ in } }
    var openedURLs: [URL] = []
    var syncedURLs: [URL] = []
    var revealedLines: [Int] = []

    func open(_ file: URL) async { openedURLs.append(file) }
    func close(_ id: UUID) async {}
    func syncDirectory(_ url: URL) { syncedURLs.append(url) }
    func sendToTerminal(_ text: String) {}
    func runInTerminal(_ command: String) {}
    func terminalCurrentSelection() -> String? { nil }
    func terminalLastCommandOutput() -> String? { nil }
    func focusTerminal() {}
    func revealSourceLine(_ line: Int) { revealedLines.append(line) }
}

private func makeTempDir() throws -> URL {
    // Resolve symlinks so constructed child URLs match what FileManager.contentsOfDirectory
    // returns — on macOS, /var/folders/… symlinks to /private/var/folders/….
    let url = FileManager.default.temporaryDirectory
        .appendingPathComponent("FT-\(UUID().uuidString)")
        .standardizedFileURL
    try FileManager.default.createDirectory(at: url, withIntermediateDirectories: true)
    return url
}

private func removeItem(_ url: URL) {
    try? FileManager.default.removeItem(at: url)
}

