// MARK: - FileTreeNode

struct FileTreeNodeTests {

    private func makeNode(
        url: URL = URL(fileURLWithPath: "/tmp/test.md"),
        name: String = "test.md",
        isDirectory: Bool = false,
        children: [FileTreeNode]? = nil,
        fileType: FileType = .markdown,
        modDate: Date? = nil,
        isReadable: Bool = true
    ) -> FileTreeNode {
        FileTreeNode(
            id: url, name: name, isDirectory: isDirectory,
            children: children, fileType: fileType,
            modificationDate: modDate, isReadable: isReadable
        )
    }

    @Test func init_storesAllFields() {
        let url = URL(fileURLWithPath: "/tmp/foo.txt")
        let date = Date(timeIntervalSince1970: 1_000_000)
        let node = makeNode(url: url, name: "foo.txt", fileType: .text, modDate: date)
        #expect(node.id == url)
        #expect(node.name == "foo.txt")
        #expect(!node.isDirectory)
        #expect(node.fileType == .text)
        #expect(node.modificationDate == date)
        #expect(node.isReadable)
    }

    @Test func icon_directoryWithChildren_isFolderFill() {
        let child = makeNode()
        let node = makeNode(isDirectory: true, children: [child], fileType: .unknown)
        #expect(node.icon == "folder.fill")
    }

    @Test func icon_directoryNilChildren_isFolder() {
        let node = makeNode(isDirectory: true, children: nil, fileType: .unknown)
        #expect(node.icon == "folder")
    }

    @Test func icon_directoryEmptyChildren_isFolder() {
        let node = makeNode(isDirectory: true, children: [], fileType: .unknown)
        #expect(node.icon == "folder")
    }

    @Test func icon_unreadable_isLockDoc() {
        let node = makeNode(isReadable: false)
        #expect(node.icon == "lock.doc")
    }

    @Test func icon_markdown_isDocRichtext() {
        #expect(makeNode(fileType: .markdown).icon == "doc.richtext")
    }

    @Test func icon_html_isChevronSlash() {
        #expect(makeNode(fileType: .html).icon == "chevron.left.slash.chevron.right")
    }

    @Test func icon_pdf_isDocTextECG() {
        #expect(makeNode(fileType: .pdf).icon == "doc.text.below.ecg")
    }

    @Test func icon_ascii_isDocTextImage() {
        #expect(makeNode(fileType: .ascii).icon == "doc.text.image")
    }

    @Test func icon_text_isDocPlaintext() {
        #expect(makeNode(fileType: .text).icon == "doc.plaintext")
    }

    @Test func icon_image_isPhoto() {
        #expect(makeNode(fileType: .image).icon == "photo")
    }

    @Test func icon_binary_isDocZipper() {
        #expect(makeNode(fileType: .binary).icon == "doc.zipper")
    }

    @Test func icon_unknown_isDoc() {
        #expect(makeNode(fileType: .unknown).icon == "doc")
    }

    @Test func equatable_identicalNodes_areEqual() {
        let url = URL(fileURLWithPath: "/tmp/a.txt")
        let a = makeNode(url: url, name: "a.txt")
        let b = makeNode(url: url, name: "a.txt")
        #expect(a == b)
    }

    @Test func equatable_differentURL_isNotEqual() {
        let a = makeNode(url: URL(fileURLWithPath: "/tmp/a.txt"), name: "a.txt")
        let b = makeNode(url: URL(fileURLWithPath: "/tmp/b.txt"), name: "b.txt")
        #expect(a != b)
    }

    @Test func hashable_identicalNodes_deduplicateInSet() {
        let url = URL(fileURLWithPath: "/tmp/a.txt")
        var set = Set<FileTreeNode>()
        set.insert(makeNode(url: url, name: "a.txt"))
        set.insert(makeNode(url: url, name: "a.txt"))
        #expect(set.count == 1)
    }
}

